// This node waits for both queries to arrive
// n8n merges the inputs - we process in the next node
return [$input.item];

const leadItems = $('Query Lead Status Counts').all().map(i => i.json);
const emailLogItems = $('Query Email Log (7 Days)').all().map(i => i.json);

// Flatten arrays if nested
const leads = leadItems.flat();
const emailLogs = emailLogItems.flat();

// Count leads by status
const statusCounts = {};
for (const lead of leads) {
  const s = lead.status || 'unknown';
  statusCounts[s] = (statusCounts[s] || 0) + 1;
}

// Calculate 7-day email metrics
const totalSent7d = emailLogs.length;
const replied = emailLogs.filter(e => ['replied', 'positive', 'demo_booked', 'converted'].includes(e.status)).length;
const positive = emailLogs.filter(e => ['positive', 'demo_booked', 'converted'].includes(e.status)).length;
const demoBooked = emailLogs.filter(e => e.status === 'demo_booked' || e.status === 'converted').length;
const converted = emailLogs.filter(e => e.status === 'converted').length;

// By region breakdown
const byRegion = {};
for (const log of emailLogs) {
  const region = log.region || 'unknown';
  if (!byRegion[region]) {
    byRegion[region] = { sent: 0, replied: 0, positive: 0 };
  }
  byRegion[region].sent++;
  if (['replied', 'positive', 'demo_booked', 'converted'].includes(log.status)) byRegion[region].replied++;
  if (['positive', 'demo_booked', 'converted'].includes(log.status)) byRegion[region].positive++;
}

const metrics = {
  emails_sent_7d: totalSent7d,
  reply_rate: totalSent7d > 0 ? (replied / totalSent7d * 100).toFixed(1) + '%' : '0%',
  positive_rate: totalSent7d > 0 ? (positive / totalSent7d * 100).toFixed(1) + '%' : '0%',
  demo_book_rate: totalSent7d > 0 ? (demoBooked / totalSent7d * 100).toFixed(1) + '%' : '0%',
  conversion_rate: totalSent7d > 0 ? (converted / totalSent7d * 100).toFixed(1) + '%' : '0%',
  by_region: byRegion,
  lead_pipeline: statusCounts,
  total_leads: Object.values(statusCounts).reduce((a, b) => a + b, 0),
  calculated_at: new Date().toISOString()
};

return [{ json: metrics }];

const m = $('Calculate Metrics').first().json;

const regionReport = Object.entries(m.by_region || {}).map(([region, data]) => {
  return `  ${region}: ${data.sent} sent, ${data.replied} replied, ${data.positive} positive`;
}).join('\n');

const pipelineReport = Object.entries(m.lead_pipeline || {}).map(([status, count]) => {
  return `  ${status}: ${count}`;
}).join('\n');

const report = `Cold Email Metrics (7-Day)\n` +
  `==========================\n` +
  `Sent: ${m.emails_sent_7d}\n` +
  `Reply Rate: ${m.reply_rate}\n` +
  `Positive Rate: ${m.positive_rate}\n` +
  `Demo Book Rate: ${m.demo_book_rate}\n` +
  `Conversion Rate: ${m.conversion_rate}\n` +
  `Total Pipeline Leads: ${m.total_leads}\n\n` +
  `By Region:\n${regionReport || '  No regional data'}\n\n` +
  `Pipeline:\n${pipelineReport || '  No pipeline data'}`;

return [{ json: { report, ...m } }];
